package main

import (
	"html/template"
	"log"
	"net/http"
	"strings"
)

type Comment struct {
	Author  string
	Content template.HTML
}

var comments = []Comment{
	{
		Author:  "Alice",
		Content: template.HTML(formatComment("Hello, this is my <b>first</b> comment!\nI like Go.")),
	},
	{
		Author:  "Bob",
		Content: template.HTML(formatComment("I can write *bold* or _italic_ text.\nNice!")),
	},
	{
		Author:  "Charlie",
		Content: template.HTML(formatComment("Check this out: `inline code` and\nanother line.")),
	},
}

var pageTmpl = template.Must(template.New("comments").Parse(`
<!doctype html>
<html>
<head>
	<meta charset="utf-8">
	<title>Comments</title>
	<style>
		body { font-family: Arial, sans-serif; margin: 2rem; }
		.comment { border: 1px solid #ddd; padding: 1rem; margin-bottom: 1rem; border-radius: 8px; }
		.author { font-weight: bold; margin-bottom: 0.5rem; }
		.content { white-space: normal; }
	</style>
</head>
<body>
	<h1>User Comments</h1>
	{{range .}}
		<div class="comment">
			<div class="author">{{.Author}}</div>
			<div class="content">{{.Content}}</div>
		</div>
	{{else}}
		<p>No comments yet.</p>
	{{end}}
</body>
</html>`))

func formatComment(s string) string {
	s = template.HTMLEscapeString(s)
	s = strings.ReplaceAll(s, "\n", "<br>")
	s = strings.ReplaceAll(s, "*", "<b>")
	s = strings.ReplaceAll(s, "_", "<i>")
	s = strings.ReplaceAll(s, "`", "<code>")
	return s
}

func commentsHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "text/html; charset=utf-8")
	if err := pageTmpl.Execute(w, comments); err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func main() {
	http.HandleFunc("/", commentsHandler)
	log.Println("listening on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}